def compute_segment_stats(df, filters_dict):
    results = []

    for segment_name, filter_spec in filters_dict.items():
        mask = pd.Series([True] * len(df), index=df.index)

        for col, condition in filter_spec.items():
            if isinstance(condition, tuple) and len(condition) == 2:
                # Range filter: (min, max)
                mask = mask & (df[col] >= condition[0]) & (df[col] <= condition[1])
            elif isinstance(condition, list):
                # Membership filter: [val1, val2, ...]
                mask = mask & df[col].isin(condition)
            else:
                # Exact match
                mask = mask & (df[col] == condition)

        segment_df = df[mask]
        count = len(segment_df)
        avg_loan = segment_df['loan_amount'].mean() if count > 0 else 0
        avg_score = segment_df['credit_score'].mean() if count > 0 else 0

        approval_rate = None
        if 'defaulted' in segment_df.columns and count > 0:
            approval_rate = 1 - segment_df['defaulted'].mean()

        results.append({
            'segment_name': segment_name,
            'count': count,
            'approval_rate': round(approval_rate, 4) if approval_rate is not None else None,
            'avg_loan_amount': round(avg_loan, 2),
            'avg_credit_score': round(avg_score, 1)
        })

    return pd.DataFrame(results)
